SELECT AVG(effect_size) AS average_effect_size
FROM predictors
WHERE category = 'content' AND effect_sign = 'positive';

SELECT predictor_name, description, effect_size, effect_sign
FROM predictors
ORDER BY effect_size DESC;

SELECT AVG(effect_size) AS average_effect_size
FROM predictors
WHERE category = 'content';

SELECT behavior_value
FROM customer_behavior
WHERE behavior_date = '2022-01-01';

SELECT customer_id, AVG(behavior_value) AS average_behavior_value
FROM customer_behavior
GROUP BY customer_id;

SELECT COUNT(DISTINCT customer_id) AS active_customer_count
FROM customer_lifecycle
WHERE lifecycle_stage = 'active';

SELECT category, COUNT(*) AS predictor_count
FROM predictors
GROUP BY category;

SELECT AVG(behavior_value) AS average_behavior_value
FROM customer_behavior
WHERE predictor_id = 1;

SELECT predictor_name
FROM predictors
WHERE predictor_name = 'Avg. monthly change in no. movies' AND effect_size > 0.5;
